fn cmp(&self, other: &Self) -> std::cmp::Ordering {
    self.0.cmp(&other.0)
        .then_with(|| self.1.cmp(&other.1))
        .then_with(|| self.2.val.partial_cmp(&other.2.val).unwrap_or(std::cmp::Ordering::Equal))
        .then_with(|| self.3.cmp(&other.3))
}

